import { json } from '@sveltejs/kit';
import type { RequestHandler } from './$types.js';
import { sql } from 'drizzle-orm';
import { db } from '$lib/db/index.js';
import { createLogger } from '$lib/server/logger.js';
// @ts-expect-error — Vite handles JSON imports natively
import pkg from '../../../../package.json';

const logger = createLogger('health');

// ── Types ────────────────────────────────────────────────────────────────────

export interface HealthResponse {
	status: 'ok';
	version: string;
	uptime: number;
	db: 'connected' | 'error';
}

export interface DbClient {
	run: (query: ReturnType<typeof sql>) => unknown;
}

// ── Health check logic (exported for testability) ────────────────────────────

/**
 * Execute a lightweight DB probe. Returns 'connected' on success, 'error' on failure.
 * Extracted so tests can inject a mock DbClient without touching the global singleton.
 */
export async function healthCheck(database: DbClient): Promise<{ db: 'connected' | 'error' }> {
	try {
		await database.run(sql`SELECT 1`);
		return { db: 'connected' };
	} catch {
		return { db: 'error' };
	}
}

// ── Handler ──────────────────────────────────────────────────────────────────

export const GET: RequestHandler = async () => {
	const { db: dbStatus } = await healthCheck(db);

	const response: HealthResponse = {
		status: 'ok',
		version: pkg.version,
		uptime: process.uptime(),
		db: dbStatus
	};

	logger.debug('Health check', { db: dbStatus });

	return json(response);
};

import { json } from '@sveltejs/kit';
import type { RequestHandler } from './$types.js';
import { createSession, validatePassword, buildSessionCookie, AUTH_COOKIE_NAME } from '$lib/server/auth.js';
import { loginRequestSchema } from '$lib/schemas/auth.js';

export const POST: RequestHandler = async ({ request, cookies }) => {
	// 1. Parse and validate request body
	let body: unknown;
	try {
		body = await request.json();
	} catch {
		return json({ error: 'invalid_json', message: 'Request body must be valid JSON' }, { status: 400 });
	}

	const parsed = loginRequestSchema.safeParse(body);
	if (!parsed.success) {
		return json(
			{
				error: 'validation_error',
				message: 'Validation failed',
				details: parsed.error.issues.map((i) => ({
					field: i.path.join('.'),
					message: i.message
				}))
			},
			{ status: 400 }
		);
	}

	// 2. Validate password
	if (!validatePassword(parsed.data.password)) {
		return json({ error: 'unauthorized', message: '密码错误' }, { status: 401 });
	}

	// 3. Create session
	const session = createSession();

	// 4. Set HttpOnly session cookie
	cookies.set(AUTH_COOKIE_NAME, session.signedToken, {
		path: '/',
		httpOnly: true,
		secure: process.env.NODE_ENV === 'production',
		sameSite: 'lax',
		maxAge: Math.floor(session.maxAge / 1000)
	});

	// 5. Return success with token
	return json({ token: session.signedToken });
};

