import { createHmac, randomBytes, timingSafeEqual } from 'node:crypto';

// ── Configuration ───────────────────────────────────────────────────────────

function getEnvOrThrow(key: string): string {
	const val = process.env[key];
	if (!val) throw new Error(`Missing required env var: ${key}`);
	return val;
}

/** Derive a signing secret from ADMIN_PASSWORD (always available in production). */
function getSigningSecret(): string {
	const pw = process.env.ADMIN_PASSWORD || '';
	// Use HMAC of a fixed salt with the password as key to derive a stable secret
	return createHmac('sha256', pw).update('milestone-tracker-session-salt').digest('hex');
}

/** Parse comma-separated API_KEYS from .env */
function getApiKeys(): string[] {
	const raw = process.env.API_KEYS || '';
	return raw
		.split(',')
		.map((k) => k.trim())
		.filter(Boolean);
}

// ── Session Management (stateless signed tokens) ────────────────────────────
// Token format: `{randomHex}.{hmac-sha256-hex}`
// This is stateless — no server-side session store needed.

const SESSION_COOKIE_NAME = 'mt_session';
const SESSION_MAX_AGE_MS = 24 * 60 * 60 * 1000; // 24 hours

export interface Session {
	token: string;
	signedToken: string;
	createdAt: number;
	maxAge: number;
}

/** Create a new signed session token. */
export function createSession(): Session {
	const token = randomBytes(32).toString('hex');
	const signature = createHmac('sha256', getSigningSecret()).update(token).digest('hex');
	const signedToken = `${token}.${signature}`;
	return {
		token,
		signedToken,
		createdAt: Date.now(),
		maxAge: SESSION_MAX_AGE_MS
	};
}

/** Verify a signed session token. Returns true if valid and not expired. */
export function verifySession(signedToken: string, maxAge: number = SESSION_MAX_AGE_MS): boolean {
	const lastDot = signedToken.lastIndexOf('.');
	if (lastDot === -1) return false;

	const token = signedToken.substring(0, lastDot);
	const providedSignature = signedToken.substring(lastDot + 1);

	if (!token || !providedSignature) return false;

	const expectedSignature = createHmac('sha256', getSigningSecret()).update(token).digest('hex');

	try {
		return timingSafeEqual(
			Buffer.from(providedSignature, 'hex'),
			Buffer.from(expectedSignature, 'hex')
		);
	} catch {
		return false;
	}
}

/** Destroy a session by returning a cookie that immediately expires. */
export function destroySessionCookie(): { name: string; value: string; options: SessionCookieOptions } {
	return {
		name: SESSION_COOKIE_NAME,
		value: '',
		options: {
			path: '/',
			httpOnly: true,
			secure: process.env.NODE_ENV === 'production',
			sameSite: 'lax',
			maxAge: 0
		}
	};
}

/** Build a Set-Cookie header value for a new session. */
export function buildSessionCookie(session: Session): string {
	const opts = sessionCookieOptions(session.maxAge);
	return `${SESSION_COOKIE_NAME}=${session.signedToken}; Path=${opts.path}; HttpOnly${opts.secure ? '; Secure' : ''}; SameSite=${opts.sameSite}; Max-Age=${Math.floor(opts.maxAge / 1000)}`;
}

// ── Bearer Token Validation ─────────────────────────────────────────────────

/** Validate a Bearer token against API_KEYS from .env. */
export function validateBearerToken(token: string): boolean {
	const apiKeys = getApiKeys();
	const tokenBuf = Buffer.from(token);
	return apiKeys.some((key) => {
		const keyBuf = Buffer.from(key);
		if (tokenBuf.length !== keyBuf.length) return false;
		return timingSafeEqual(tokenBuf, keyBuf);
	});
}

// ── Cookie Helpers ──────────────────────────────────────────────────────────

export interface SessionCookieOptions {
	path: string;
	httpOnly: boolean;
	secure: boolean;
	sameSite: 'lax' | 'strict';
	maxAge: number; // seconds
}

function sessionCookieOptions(maxAgeMs: number): SessionCookieOptions {
	return {
		path: '/',
		httpOnly: true,
		secure: process.env.NODE_ENV === 'production',
		sameSite: 'lax',
		maxAge: Math.floor(maxAgeMs / 1000)
	};
}

// ── Auth Middleware Logic ────────────────────────────────────────────────────
// Extracted as pure functions for testability. Used by hooks.server.ts.

export type AuthResult =
	| { authenticated: true; method: 'cookie' | 'bearer' }
	| { authenticated: false; reason: string };

/** Extract the signed session token from a Cookie header string. */
export function extractSessionCookie(cookieHeader: string | null): string | null {
	if (!cookieHeader) return null;
	const match = cookieHeader.match(/(?:^|;\s*)mt_session=([^;]+)/);
	return match ? match[1] : null;
}

/** Extract Bearer token from Authorization header. */
export function extractBearerToken(authHeader: string | null): string | null {
	if (!authHeader) return null;
	const parts = authHeader.split(' ');
	if (parts.length !== 2 || parts[0] !== 'Bearer') return null;
	return parts[1] || null;
}

/**
 * Check authentication from cookie and/or authorization headers.
 * Returns the auth result without performing any side effects.
 */
export function checkAuth(
	cookieHeader: string | null,
	authHeader: string | null
): AuthResult {
	// 1. Try Bearer token first (CLI/API usage)
	const bearer = extractBearerToken(authHeader);
	if (bearer) {
		if (validateBearerToken(bearer)) {
			return { authenticated: true, method: 'bearer' };
		}
		return { authenticated: false, reason: 'invalid_bearer_token' };
	}

	// 2. Try session cookie (Web usage)
	const sessionToken = extractSessionCookie(cookieHeader);
	if (sessionToken) {
		if (verifySession(sessionToken)) {
			return { authenticated: true, method: 'cookie' };
		}
		return { authenticated: false, reason: 'invalid_session' };
	}

	return { authenticated: false, reason: 'no_credentials' };
}

/** Validate a login password against ADMIN_PASSWORD env var. */
export function validatePassword(password: string): boolean {
	const adminPassword = process.env.ADMIN_PASSWORD;
	if (!adminPassword) return false;
	const pwBuf = Buffer.from(password);
	const adminBuf = Buffer.from(adminPassword);
	if (pwBuf.length !== adminBuf.length) return false;
	return timingSafeEqual(pwBuf, adminBuf);
}

// ── Exports for hooks ───────────────────────────────────────────────────────

export const AUTH_COOKIE_NAME = SESSION_COOKIE_NAME;

import { z } from 'zod';
import { milestoneStatusEnum } from '../db/schema.js';
import { sourceMdSchema, milestoneIdSchema } from './common.js';

// ── Create ──────────────────────────────────────────────────────────────────

export const createMilestoneSchema = z.object({
	title: z.string().min(1, 'Title is required').max(200, 'Title must be under 200 characters'),
	sourceMd: sourceMdSchema.optional(),
	gitUrl: z.string().url('Invalid URL').optional().or(z.literal(''))
});
export type CreateMilestoneInput = z.infer<typeof createMilestoneSchema>;

// ── Update ──────────────────────────────────────────────────────────────────

export const updateMilestoneSchema = z.object({
	title: z.string().min(1).max(200).optional(),
	sourceMd: sourceMdSchema.optional(),
	gitUrl: z.string().url().optional().or(z.literal('')),
	status: z.enum(milestoneStatusEnum).optional()
});
export type UpdateMilestoneInput = z.infer<typeof updateMilestoneSchema>;

// ── Response ────────────────────────────────────────────────────────────────

export const milestoneResponseSchema = z.object({
	id: milestoneIdSchema,
	title: z.string(),
	sourceMd: z.string().nullable(),
	gitUrl: z.string().nullable(),
	status: z.enum(milestoneStatusEnum),
	createdAt: z.string().datetime() // ISO 8601
});
export type MilestoneResponse = z.infer<typeof milestoneResponseSchema>;

import { defineConfig } from 'vitest/config';
import { sveltekit } from '@sveltejs/kit/vite';

export default defineConfig({
	plugins: [sveltekit()],
	test: {
		environment: 'jsdom',
		include: ['src/**/*.{test,spec}.{js,ts}']
	}
});

import { sqliteTable, text, integer, index } from 'drizzle-orm/sqlite-core';
import { sql } from 'drizzle-orm';

// ── Status enums (stored as text in SQLite, validated by Zod at app layer) ──

export const milestoneStatusEnum = ['draft', 'in-progress', 'completed', 'archived'] as const;
export type MilestoneStatus = (typeof milestoneStatusEnum)[number];

export const moduleStatusEnum = ['draft', 'in-progress', 'completed'] as const;
export type ModuleStatus = (typeof moduleStatusEnum)[number];

export const taskStatusEnum = [
	'todo',
	'in-progress',
	'blocked',
	'review',
	'done',
	'skipped'
] as const;
export type TaskStatus = (typeof taskStatusEnum)[number];

// ── Milestone ────────────────────────────────────────────────────────────────
// Primary entity. ID format: MS-{seq} (e.g. MS-1, MS-2).

export const milestones = sqliteTable(
	'milestones',
	{
		id: text('id').primaryKey(), // MS-{seq}
		title: text('title').notNull(),
		sourceMd: text('source_md'),
		gitUrl: text('git_url'),
		status: text('status', { enum: milestoneStatusEnum }).notNull().default('draft'),
		createdAt: integer('created_at', { mode: 'timestamp' })
			.notNull()
			.default(sql`(unixepoch())`)
	},
	(table) => [index('milestone_status_idx').on(table.status)]
);

// ── Module ───────────────────────────────────────────────────────────────────
// Groups tasks within a milestone. ID format: MOD-{milestone_seq}-{seq}.

export const modules = sqliteTable(
	'modules',
	{
		id: text('id').primaryKey(), // MOD-{ms_seq}-{seq}
		milestoneId: text('milestone_id')
			.notNull()
			.references(() => milestones.id, { onDelete: 'cascade' }),
		name: text('name').notNull(),
		description: text('description'),
		status: text('status', { enum: moduleStatusEnum }).notNull().default('draft'),
		sortOrder: integer('sort_order').notNull().default(0)
	},
	(table) => [
		index('module_milestone_id_idx').on(table.milestoneId),
		index('module_status_idx').on(table.status)
	]
);

// ── Task ─────────────────────────────────────────────────────────────────────
// Atomic unit of work. ID format: TASK-{global_seq}.
// short_id is a global auto-increment for human-friendly references.

export const tasks = sqliteTable(
	'tasks',
	{
		id: text('id').primaryKey(), // TASK-{global_seq}
		shortId: integer('short_id').notNull().unique(), // global auto-increment
		moduleId: text('module_id')
			.notNull()
			.references(() => modules.id, { onDelete: 'cascade' }),
		title: text('title').notNull(),
		description: text('description'),
		references: text('references'), // JSON or text blob
		status: text('status', { enum: taskStatusEnum }).notNull().default('todo'),
		assignee: text('assignee'),
		subTotal: integer('sub_total').notNull().default(0),
		subDone: integer('sub_done').notNull().default(0),
		progressMessage: text('progress_message'),
		commitHash: text('commit_hash'),
		createdAt: integer('created_at', { mode: 'timestamp' })
			.notNull()
			.default(sql`(unixepoch())`),
		updatedAt: integer('updated_at', { mode: 'timestamp' })
			.notNull()
			.default(sql`(unixepoch())`),
		reportedAt: integer('reported_at', { mode: 'timestamp' })
	},
	(table) => [
		index('task_status_module_idx').on(table.status, table.moduleId),
		index('task_status_reported_idx').on(table.status, table.reportedAt),
		index('task_module_id_idx').on(table.moduleId),
		index('task_short_id_idx').on(table.shortId)
	]
);

// ── Type exports for use in application code ──

export type Milestone = typeof milestones.$inferSelect;
export type NewMilestone = typeof milestones.$inferInsert;
export type Module = typeof modules.$inferSelect;
export type NewModule = typeof modules.$inferInsert;
export type Task = typeof tasks.$inferSelect;
export type NewTask = typeof tasks.$inferInsert;

import { z } from 'zod';

// ── Login request ───────────────────────────────────────────────────────────

export const loginRequestSchema = z.object({
	password: z.string().min(1, 'Password is required')
});
export type LoginRequest = z.infer<typeof loginRequestSchema>;

// ── Login response ──────────────────────────────────────────────────────────

export const loginResponseSchema = z.object({
	token: z.string().min(1)
});
export type LoginResponse = z.infer<typeof loginResponseSchema>;

import { redirect, json } from '@sveltejs/kit';
import type { Handle } from '@sveltejs/kit';
import { checkAuth } from '$lib/server/auth.js';
import { createLogger } from '$lib/server/logger.js';

const logger = createLogger('request');

/** Paths to skip from request logging (static assets, health checks). */
const SKIP_LOG_PATHS = ['/_app/', '/favicon', '/api/health'];

export const handle: Handle = async ({ event, resolve }) => {
	const { url, request, cookies } = event;
	const path = url.pathname;

	// Skip auth for static assets and prerendered pages
	if (path.startsWith('/_app/') || path.startsWith('/favicon')) {
		return resolve(event);
	}

	// Skip request logging for health checks and static assets
	const shouldLog = !SKIP_LOG_PATHS.some((p) => path === p || path.startsWith(p));

	// Measure request duration
	const start = performance.now();

	// Log incoming request
	if (shouldLog) {
		const userAgent = request.headers.get('user-agent') ?? 'unknown';
		logger.info('Incoming request', { method: request.method, path, userAgent });
	}

	// Public routes — no auth required
	const publicRoutes = ['/login', '/api/auth/login', '/api/auth/logout', '/api/health'];
	if (publicRoutes.some((r) => path === r || path.startsWith(r + '/'))) {
		// If already authenticated and visiting /login, redirect to home
		if (path === '/login') {
			const cookieHeader = request.headers.get('cookie');
			const authHeader = request.headers.get('authorization');
			const result = checkAuth(cookieHeader, authHeader);
			if (result.authenticated) {
				throw redirect(302, '/');
			}
		}
		return logResponse(resolve(event), start, request.method, path, shouldLog);
	}

	// ── API routes: require auth (cookie or bearer) ──
	if (path.startsWith('/api/')) {
		const cookieHeader = request.headers.get('cookie');
		const authHeader = request.headers.get('authorization');
		const result = checkAuth(cookieHeader, authHeader);

		if (!result.authenticated) {
			// Return 401 JSON for API routes
			const response = json(
				{
					error: 'unauthorized',
					message: result.reason === 'invalid_bearer_token' ? '无效的 API Key' : '请先登录'
				},
				{ status: 401 }
			);
			return logResponse(Promise.resolve(response), start, request.method, path, shouldLog);
		}

		// Attach auth method to locals for downstream use
		event.locals.authMethod = result.method;
		return logResponse(resolve(event), start, request.method, path, shouldLog);
	}

	// ── Page routes: require cookie auth, redirect to /login ──
	const cookieHeader = request.headers.get('cookie');
	const authHeader = request.headers.get('authorization');
	const result = checkAuth(cookieHeader, authHeader);

	if (!result.authenticated) {
		throw redirect(302, '/login');
	}

	event.locals.authMethod = result.method;
	return logResponse(resolve(event), start, request.method, path, shouldLog);
};

/** Wrap response promise with duration logging. */
function logResponse(
	responsePromise: Response | Promise<Response>,
	start: number,
	method: string,
	path: string,
	shouldLog: boolean
): Response | Promise<Response> {
	if (!shouldLog) return responsePromise;

	return Promise.resolve(responsePromise).then((response) => {
		const durationMs = Math.round(performance.now() - start);
		logger.info('Request completed', { method, path, status: response.status, durationMs });
		return response;
	});
}

